import React, { useEffect, useState } from 'react';
import { getTasks, getUsers } from '../services/api';

const HomePage: React.FC = () => {
  const [taskCount, setTaskCount] = useState(0);
  const [userCount, setUserCount] = useState(0);
  const [completedCount, setCompletedCount] = useState(0);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const tasks = await getTasks();
        const users = await getUsers();
        setTaskCount(tasks.length);
        setUserCount(users.length);
        setCompletedCount(tasks.filter((t: any) => t.status === 'completed').length);
      } catch (err) {
        console.error('Failed to load stats');
      }
    };
    fetchStats();
  }, []);

  const stats = [
    { label: 'Total Users', value: userCount, color: '#2563eb' },
    { label: 'Total Tasks', value: taskCount, color: '#7c3aed' },
    { label: 'Completed Tasks', value: completedCount, color: '#059669' },
  ];

  return (
    <div style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
      <h1 style={{ marginBottom: '0.5rem' }}>RL Training Data Platform</h1>
      <p style={{ color: '#666', marginBottom: '2.5rem', fontSize: '1.05rem' }}>
        A platform for collecting human feedback to train AI agents through
        reinforcement learning from human feedback (RLHF).
      </p>

      {/* Stats */}
      <div style={{ display: 'flex', gap: '1.5rem', marginBottom: '3rem' }}>
        {stats.map(stat => (
          <div key={stat.label} style={{
            flex: 1,
            background: 'white',
            border: '1px solid #eee',
            borderRadius: '10px',
            padding: '1.5rem',
            textAlign: 'center',
            boxShadow: '0 1px 3px rgba(0,0,0,0.05)'
          }}>
            <div style={{
              fontSize: '2.5rem',
              fontWeight: 700,
              color: stat.color,
              marginBottom: '0.4rem'
            }}>
              {stat.value}
            </div>
            <div style={{ color: '#666', fontSize: '0.9rem' }}>{stat.label}</div>
          </div>
        ))}
      </div>

      {/* How it works */}
      <h2 style={{ marginBottom: '1rem', fontSize: '1.15rem' }}>How It Works</h2>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        {[
          { step: '01', title: 'Researcher creates a task', desc: 'A prompt is created that AI models will answer' },
          { step: '02', title: 'AI models respond', desc: 'Multiple AI models generate responses to the prompt' },
          { step: '03', title: 'Annotators rate responses', desc: 'Human annotators score each response 1-5 with feedback' },
          { step: '04', title: 'Data exported for training', desc: 'Clean preference data is used to fine-tune AI models' },
        ].map(item => (
          <div key={item.step} style={{
            display: 'flex',
            alignItems: 'flex-start',
            gap: '1rem',
            padding: '1rem',
            background: 'white',
            border: '1px solid #eee',
            borderRadius: '8px',
          }}>
            <span style={{
              background: '#0f172a',
              color: 'white',
              borderRadius: '6px',
              padding: '0.3rem 0.6rem',
              fontSize: '0.8rem',
              fontWeight: 700,
              flexShrink: 0
            }}>
              {item.step}
            </span>
            <div>
              <p style={{ fontWeight: 600, marginBottom: '0.2rem' }}>{item.title}</p>
              <p style={{ color: '#666', fontSize: '0.9rem' }}>{item.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default HomePage;
